sql:
SELECT organism_id, organism_name
FROM organisms
ORDER BY organism_id DESC;

SELECT DISTINCT organism_name
FROM organisms
ORDER BY organism_name ASC;

SELECT DISTINCT organism_name
FROM organisms
WHERE organism_name IN (SELECT DISTINCT disease_name FROM diseases);

SELECT organism_name
FROM organisms
WHERE scientific_name = 'Homo sapiens';

SELECT user_name
FROM users
WHERE user_id IN (
  SELECT user_id
  FROM experiments
);

SELECT disease_name
FROM diseases
WHERE disease_subcategory = 'Virus';

SELECT e.experiment_id, e.experiment_name, ar.analysis_result_name
FROM experiments e
LEFT JOIN analysis_results ar ON e.experiment_id = ar.analysis_result_experiment;

SELECT organism_name AS "Name" FROM organisms
UNION
SELECT cell_line_name AS "Name" FROM cell_lines;

SELECT COUNT(DISTINCT organism_id), organism_name
FROM organisms
GROUP BY organism_name;

SELECT experiment_name 
FROM experiments 
ORDER BY experiment_name ASC;

SELECT organism_name, scientific_name, (SELECT COUNT(*) FROM organisms WHERE organism_id > 5) AS total_organisms
FROM organisms
WHERE organism_id > 5;

SELECT organism_name, COUNT(*) as organism_count
FROM organisms
WHERE organism_id = 123;

SELECT organism_id, organism_name, scientific_name
FROM organisms
WHERE organism_id = 1;
